(window.webpackJsonp=window.webpackJsonp||[]).push([[124],{937:function(n,e,t){"use strict";t.r(e);var r=t(1),i=function(n){n.options.__data__block__={presentation_1a96284a:"\n---\n\n## 110-平衡二叉树\n\n![](./img/110/1.png)\n\n--\n\n![](./img/110/2.png)\n\n--\n\n```java\nclass Solution {\n    public boolean isBalanced(TreeNode root) {\n        // 后序\n        if (traverse(root) < 0){\n            return false;\n        } else {\n            return true;\n        }\n    }\n\n    int traverse(TreeNode node){\n        if (null == node){\n            return 0;\n        }\n        int leftH = traverse(node.left);\n        int rightH = traverse(node.right);\n        if (leftH == -1 || rightH == -1 || Math.abs(rightH - leftH) > 1){\n            // 不合格\n            return -1;\n        } else {\n            // 当前节点为root的子树合格\n            return Math.max(leftH, rightH) +1;\n        }\n\n    }\n}\n```\n\n---\n\n## 108-将有序数组转换为二叉搜索树\n\n![](./img/108/1.png)\n\n--\n\n```java\nclass Solution {\n    public TreeNode sortedArrayToBST(int[] nums) {\n        return buildTree(nums, 0, nums.length-1);\n    }\n\n    TreeNode buildTree(int[] nums, int start, int end){\n        // 递归找中位数\n        if (start > end){\n            return null;\n        }\n        int median = (end - start)/2;\n        TreeNode node = new TreeNode(nums[median]);\n        node.left = buildTree(nums, start, median -1);\n        node.right = buildTree(nums, median +1, end);\n        return node; \n    }\n}\n```\n\n---\n\n## 109-有序链表转换二叉搜索树\n\n![](./img/109/1.png)\n\n--\n\n将109转成108解题。\n```java\nclass Solution {\n    List<Integer> valList = new ArrayList();\n    public TreeNode sortedListToBST(ListNode head) {\n        while (null != head){\n            valList.add(head.val);\n            head = head.next;\n        }\n        return buildTree(0, valList.size() - 1);\n    }\n\n    TreeNode buildTree(int start, int end){\n        if (start > end){\n            return null;\n        }\n        int mid = (end + start)/2;\n        TreeNode node = new TreeNode(valList.get(mid));\n        node.left = buildTree(start, mid - 1);\n        node.right = buildTree(mid + 1, end);\n        return node;\n    }\n}\n```\n\n--\n\n中序遍历+中位数\n```java\nclass Solution {\n    ListNode globalHead;\n\n    public TreeNode sortedListToBST(ListNode head) {\n        globalHead = head;\n        int length = getLength(head);\n        return buildTree(0, length - 1);\n    }\n\n    public int getLength(ListNode head) {\n        int ret = 0;\n        while (head != null) {\n            ++ret;\n            head = head.next;\n        }\n        return ret;\n    }\n\n    public TreeNode buildTree(int left, int right) {\n        if (left > right) {\n            return null;\n        }\n        int mid = (left + right + 1) / 2;\n        TreeNode root = new TreeNode();\n        root.left = buildTree(left, mid - 1);\n        root.val = globalHead.val;\n        globalHead = globalHead.next;\n        root.right = buildTree(mid + 1, right);\n        return root;\n    }\n}\n```\n\n\n"}},a=Object(r.a)({},(function(){var n=this.$createElement,e=this._self._c||n;return e("ContentSlotsDistributor",{attrs:{"slot-key":this.$parent.slotKey}},[e("Presentation",{key:"presentation_1a96284a",attrs:{id:"presentation_1a96284a",code:this.$dataBlock.presentation_1a96284a,theme:"auto"}})],1)}),[],!1,null,null,null);"function"==typeof i&&i(a);e.default=a.exports}}]);